const body = $input.item.json.body || $input.item.json;

const allowed = ['aarohaom', 'blackpanda', 'ageddentistry'];
const project = (body.projectName || '').toLowerCase().trim();

if (!allowed.includes(project)) {
  throw new Error('Invalid projectName "' + project + '". Must be one of: ' + allowed.join(', '));
}

const required = ['targetKeyword', 'serviceType', 'location'];
for (const field of required) {
  if (!body[field]) throw new Error('Missing required field: ' + field);
}

const wpConfig = {
  aarohaom: {
    url: $env.WP_AAROHAOM_URL || 'https://aarohaom.com',
    user: $env.WP_AAROHAOM_USER,
    pass: $env.WP_AAROHAOM_PASS
  },
  blackpanda: {
    url: $env.WP_BLACKPANDA_URL || 'https://blackpandaenterprises.com',
    user: $env.WP_BLACKPANDA_USER,
    pass: $env.WP_BLACKPANDA_PASS
  },
  ageddentistry: {
    url: $env.WP_AGEDDENTISTRY_URL || 'https://ageddentistry.org',
    user: $env.WP_AGEDDENTISTRY_USER,
    pass: $env.WP_AGEDDENTISTRY_PASS
  }
};

const wp = wpConfig[project];
if (!wp.url || !wp.user || !wp.pass) {
  throw new Error('Missing WordPress credentials for project: ' + project);
}

const authHeader = 'Basic ' + Buffer.from(wp.user + ':' + wp.pass).toString('base64');

return [{
  json: {
    projectName: project,
    targetKeyword: body.targetKeyword,
    serviceType: body.serviceType,
    location: body.location,
    supportingData: body.supportingData || '',
    faqQuestions: body.faqQuestions || [],
    wpUrl: wp.url,
    authHeader,
    requestId: Date.now().toString()
  }
}];

const d = $('Validate Input').item.json;
const kb = $input.item.json || {};

// Build brand context from knowledge base
const brandContext = kb.brand_summary ? `
BRAND CONTEXT (MUST follow these guidelines):
- Brand Summary: ${kb.brand_summary}
- Target Audience: ${kb.ideal_customer || 'Not specified'}
- Brand Voice: ${kb.brand_voice || 'Professional'}
- Unique Value Proposition: ${kb.unique_value_proposition || 'Not specified'}
- ALWAYS USE these words/phrases: ${JSON.stringify(kb.words_always_use || [])}
- NEVER USE these words: ${JSON.stringify(kb.words_never_use || [])}
- Proof Points to reference: ${JSON.stringify(kb.proof_points || [])}
` : '';

const prompt = `You are an expert SEO copywriter. Generate a complete, SEO-optimised WordPress page.
${brandContext}
Brief:
- Target Keyword: ${d.targetKeyword}
- Service Type: ${d.serviceType}
- Location/Variant: ${d.location}
- Supporting Data: ${d.supportingData || 'Not provided'}
- FAQ Questions to answer: ${JSON.stringify(d.faqQuestions || [])}

Output ONLY valid JSON — no markdown, no explanation:
{
  "h1": "SEO-optimised H1 (include keyword naturally)",
  "metaTitle": "Meta title under 60 chars — keyword and location",
  "metaDescription": "150-160 chars — compelling, keyword + CTA",
  "heroParagraph": "2-3 sentence hero — unique, specific, mentions location and service",
  "serviceDescription": "3-4 paragraphs HTML. Use <p> tags. Keyword 3-4 times naturally.",
  "trustPoints": ["specific credibility point 1", "point 2", "point 3"],
  "faqSchema": [{"question": "...", "answer": "2-3 sentences"}],
  "ctaSection": "<p>Strong CTA HTML. Use <strong> for key phrases.</p>",
  "pageTitle": "WordPress page title"
}

Make all content specific to ${d.serviceType} in ${d.location}.`;

return [{
  json: {
    ...d,
    brandVoice: kb.brand_voice || 'Professional',
    claudeMessages: [{ role: 'user', content: prompt }]
  }
}];

const nlData = $input.item.json;
const claudeData = $('Generate Content with Claude').item.json;
const promptData = $('Build Claude Prompt').item.json;

// Find target keyword entity salience
const targetKw = promptData.targetKeyword?.toLowerCase() || '';
const entities = nlData.entities || [];

let keywordSalience = 0;
for (const entity of entities) {
  if (entity.name?.toLowerCase().includes(targetKw) || targetKw.includes(entity.name?.toLowerCase())) {
    keywordSalience = Math.max(keywordSalience, entity.salience || 0);
  }
}

const needsRefinement = keywordSalience < 0.3 && entities.length > 0;

// Pass Claude response through unchanged, just add salience info
return [{
  json: {
    ...claudeData,
    keywordSalience,
    needsRefinement,
    nlApiWorked: entities.length > 0,
    _promptData: promptData
  }
}];

const claudeResponse = $input.item.json;
const orig = $('Build Claude Prompt').item.json;

const rawText = claudeResponse.content?.[0]?.text || '';
if (!rawText) {
  throw new Error('Claude returned empty response: ' + JSON.stringify(claudeResponse).substring(0, 300));
}

let content;
try {
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  content = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Claude returned invalid JSON: ' + rawText.substring(0, 300));
}

const trustPointsHtml = (content.trustPoints || []).map(p => '<li>' + p + '</li>').join('\n');
const faqSchemaJson = JSON.stringify({
  '@context': 'https://schema.org',
  '@type': 'FAQPage',
  mainEntity: (content.faqSchema || []).map(item => ({
    '@type': 'Question',
    name: item.question,
    acceptedAnswer: { '@type': 'Answer', text: item.answer }
  }))
});
const faqHtml = (content.faqSchema || []).map(item =>
  '<div class="faq-item"><h3>' + item.question + '</h3><p>' + item.answer + '</p></div>'
).join('\n');

const fullContent = '\n<h2>' + content.h1 + '</h2>\n<p>' + content.heroParagraph + '</p>\n\n' +
  content.serviceDescription + '\n\n<h2>Why Choose Us</h2>\n<ul>\n' + trustPointsHtml + '\n</ul>\n\n' +
  '<h2>Frequently Asked Questions</h2>\n' + faqHtml + '\n\n<div class="cta-section">\n' + content.ctaSection +
  '\n</div>\n\n<script type="application/ld+json">\n' + faqSchemaJson + '\n</script>\n';

return [{
  json: {
    projectName: orig.projectName,
    targetKeyword: orig.targetKeyword,
    serviceType: orig.serviceType,
    location: orig.location,
    wpUrl: orig.wpUrl,
    authHeader: orig.authHeader,
    requestId: orig.requestId,
    wpTitle: content.pageTitle || content.h1,
    wpContent: fullContent,
    metaTitle: content.metaTitle,
    metaDescription: content.metaDescription,
    h1: content.h1,
    keywordSalience: claudeResponse.keywordSalience || 0
  }
}];

const wpResponse = $input.item.json;
const inputData = $('Parse Claude Output').item.json;

if (!wpResponse.id) {
  throw new Error('WordPress page creation failed: ' + JSON.stringify(wpResponse).substring(0, 300));
}

const pageUrl = wpResponse.link || (inputData.wpUrl + '/?p=' + wpResponse.id);
const editUrl = inputData.wpUrl + '/wp-admin/post.php?post=' + wpResponse.id + '&action=edit';

return [{
  json: {
    ...inputData,
    wpPageId: wpResponse.id,
    wpPageUrl: pageUrl,
    wpEditUrl: editUrl,
    wpStatus: wpResponse.status
  }
}];

